vector<int> earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
    int earliest = 1, latest = 1;
    for (int i = 2; i <= n; i++) {
        if (i % 2 == 1) {
            if (firstPlayer <= i && secondPlayer >= n - i + 1) {
                earliest = i;
            }
            if (firstPlayer >= i && secondPlayer <= n - i + 1) {
                latest = i;
            }
        } else {
            if (firstPlayer <= i / 2 && secondPlayer >= n - i / 2 + 1) {
                earliest = i;
            }
            if (firstPlayer >= i / 2 && secondPlayer <= n - i / 2 + 1) {
                latest = i;
            }
        }
    }
    return {earliest, latest};
}
